GENERATED_SERVICES: dict[str, type[GeneratedServiceBase]] = {
    "batch": GeneratedBatchService,
    "bench": GeneratedBenchService,
    "ctrl": GeneratedCtrlService,
    "dc": GeneratedDcService,
    "encoder": GeneratedEncoderService,
    "gpio": GeneratedGpioService,
    "imu": GeneratedImuService,
    "led": GeneratedLedService,
    "logging": GeneratedLoggingService,
    "mcu": GeneratedMcuService,
    "observer": GeneratedObserverService,
    "perf": GeneratedPerfService,
    "pwm": GeneratedPwmService,
    "safety": GeneratedSafetyService,
    "servo": GeneratedServoService,
    "set": GeneratedSetService,
    "stepper": GeneratedStepperService,
    "system": GeneratedSystemService,
    "telemetry": GeneratedTelemetryService,
    "ultrasonic": GeneratedUltrasonicService,
    "wifi": GeneratedWifiService,
}


def get_generated_service(client: "MaraClient", category: str) -> GeneratedServiceBase | None:
    """Get a generated service instance by category."""
    service_class = GENERATED_SERVICES.get(category)
    if service_class:
        return service_class(client)
    return None


def list_categories() -> list[str]:
    """List all available service categories."""
    return list(GENERATED_SERVICES.keys())
